sql:
SELECT COUNT(DISTINCT package_id) AS total_unique_packages
FROM packages
WHERE package_name LIKE 'PEAR2%';

SELECT package_name, group_name
FROM packages
WHERE package_id = 1;

SELECT group_name, COUNT(*) AS package_count
FROM packages
GROUP BY group_name;

SELECT COUNT(extension_id) AS extension_count
FROM extensions
WHERE download_count > 1000;

SELECT COUNT(package_id) AS total_branches_and_leaves
FROM packages
WHERE group_name = 'Testing Tools';

SELECT COUNT(DISTINCT package_id) AS total_packages_with_dependency
FROM dependencies
WHERE dep_package_name = 'Some_Package';

SELECT AVG(download_count) AS average_download_count
FROM packages
WHERE group_name = 'Testing Tools' AND download_count > 1000;

